// Read open bugs from file/API
// In real setup, use HTTP Request node to call bug dashboard API
const openBugs = [
  { title: 'Login fails with special char', severity: 'high', project: 'web-login' }
];

const summary = openBugs.length > 0
  ? `🐛 ${openBugs.length} bug(s) chưa fix:\n${openBugs.map(b => `  [${b.severity.toUpperCase()}] ${b.title}`).join('\n')}`
  : '✅ Không có bug nào chưa fix!';

return [{ json: { summary, count: openBugs.length, bugs: openBugs } }];

